import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { SegmentCustomEvent } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { InstallmentsService } from "src/app/core/services/installments.service";
import { LoansService } from "src/app/core/services/loans.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { TransactionService } from "src/app/core/services/transaction.service";
import {
  bankNameValidator,
  dateTypeStringValidator,
  paidByValidator,
  penaltyTypeValidator,
  transactionAmountValidator,
} from "src/app/core/validators/custom-validators";
import { GetLoanInformationByLoanKey } from "src/app/views/Models/Loan/GetLoanInformationByLoanKey";
import { AccessRight } from "src/app/views/Models/Permissions/AccessRight";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Bank } from "src/app/views/Models/Settings/BranchReference";
import { DeleteUnexecutedPenalty } from "src/app/views/Models/Transaction/DeleteUnexecutedPenalty";
import { GetUnexecutedPenaltiesByClientKey } from "src/app/views/Models/Transaction/GetUnexecutedPenaltiesByClientKey";
import { GetUnexecutedPenaltiesPaymentByClientKey } from "src/app/views/Models/Transaction/GetUnexecutedPenaltiesPaymentByClientKey";
import { GetUnexecutedPenaltyInformationForUpdate } from "src/app/views/Models/Transaction/GetUnexecutedPenaltyInformationForUpdate";
import { InsertUnexecutedPenalties } from "src/app/views/Models/Transaction/InsertUnexecutedPenalties";
import { UpdateUnexecutedPenalty } from "src/app/views/Models/Transaction/UpdateUnexecutedPenalty";

interface segmentInformation {
  name: string;
  sourcePage: number;
  pageAction: number;
  windowCode: string;
  hasPermission: boolean;
}
interface SegmentSection {
  visible: boolean;
  allAvaliableSegments: segmentInformation[];
  selectedSegment: segmentInformation;
  disable: boolean;
}
interface ReadonlyInformation {
  clientName: string;
  clientCode: string;
  loanCode: number;
  loanAmount: number;
  loanDate: string;
  loanInterest: number;
  loanPenalities: number;
  funderName: string;
  issuingBank: string;
  loanKey: number;
}
interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface GridSection {
  insert: {
    visible: boolean;
    gridInformation: GetUnexecutedPenaltiesByClientKey[];
  };
  edit: {
    visible: boolean;
    gridInformation: GetUnexecutedPenaltiesPaymentByClientKey[];
  };
  delete: {
    visible: boolean;
    gridInformation: GetUnexecutedPenaltiesPaymentByClientKey[];
  };
}
interface LoanSection {
  visible: boolean;
  formGroup: FormGroup;
  checkIfInputsValid: boolean;
  readonlyInformation: ReadonlyInformation;
}
interface DatabaseResponses {
  loanInformation: GetLoanInformationByLoanKey;
  paidBy: StaticRef[];
  penaltyType: StaticRef[];
  bankName: Bank[];
  accessRight: AccessRight[];
  transactionInformation: GetUnexecutedPenaltyInformationForUpdate;
}
@Component({
  selector: "app-unexecuted-penalty",
  templateUrl: "./unexecuted-penalty.page.html",
  styleUrls: ["./unexecuted-penalty.page.scss"],
})
export class UnexecutedPenaltyPage implements OnInit {
  constructor(
    private transactionService: TransactionService,
    private alertService: AlertService,
    public pagingService: pagingService,
    private formBuilder: FormBuilder,
    private loanService: LoansService,
    private referencesService: ReferencesService,
    private authService: MohassilAuthService,
    public inputMaskingService: InputMaskingService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  segmentSection: SegmentSection;
  clientSearchCardSection: ClientSearchSection;
  gridCardSection: GridSection;
  loanInformationSection: LoanSection;
  databaseResponses: DatabaseResponses;
  pagingObject: { page: number };
  //#endregion

  async ngOnInit() {
    try {
      this.showLoader = true;
      this.initializeState();
      this.databaseResponses.paidBy = await this.referencesService.getPaidBy();
      this.databaseResponses.penaltyType =
        await this.referencesService.getPenaltyType();
      this.databaseResponses.bankName =
        await this.referencesService.getBanksByBankType(2); //خزينة
      this.databaseResponses.accessRight =
        await this.authService.getAccessRights();
      this.segmentSection = {
        visible: true,
        allAvaliableSegments: [
          {
            name: "ادخال حركة",
            sourcePage: 29,
            pageAction: 1,
            windowCode: "5626",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5626"
            ),
          },
          {
            name: "تعديل حركة",
            sourcePage: 30,
            pageAction: 1,
            windowCode: "5633",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5633"
            ),
          },
          {
            name: "حذف حركة",
            sourcePage: 28,
            pageAction: 1,
            windowCode: "5634",
            hasPermission: this.databaseResponses.accessRight.some(
              (x) => x.window_code === "5634"
            ),
          },
        ],
        selectedSegment: null,
        disable: false,
      };
      this.segmentSection.selectedSegment =
        this.segmentSection.allAvaliableSegments.find((x) => x.hasPermission);
    } catch (error) {
      if (error instanceof HttpErrorResponse) {
        this.alertService.showAlertError(JSON.stringify(error.error), false);
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }
  get loanSelected() {
    return this.loanInformationSection.readonlyInformation;
  }
  get loanInformation() {
    return this.databaseResponses.loanInformation;
  }
  get allSegmentsThatHavePermission() {
    return this.segmentSection.allAvaliableSegments.filter(
      (x) => x.hasPermission
    );
  }
  get readonlyInformation(): ReadonlyInformation {
    return this.loanInformationSection.readonlyInformation;
  }
  initializeState() {
    this.segmentSection = {
      visible: false,
      allAvaliableSegments: [],
      selectedSegment: null,
      disable: true,
    };
    this.clientSearchCardSection = {
      visible: true,
      clientInformation: null,
    };
    this.gridCardSection = {
      insert: {
        visible: false,
        gridInformation: [],
      },
      edit: {
        visible: false,
        gridInformation: [],
      },
      delete: {
        visible: false,
        gridInformation: [],
      },
    };
    this.loanInformationSection = {
      checkIfInputsValid: false,
      readonlyInformation: null,
      visible: false,
      formGroup: this.formBuilder.group({
        transactionAmount: [
          null,
          [
            transactionAmountValidator({
              required: true,
              valueGreaterThanZero: true,
            }),
          ],
        ],
        transactionDate: [
          null,
          dateTypeStringValidator({
            required: true,
          }),
        ],
        transactionInstallmentVoucher: [null],
        paidBy: [null, [paidByValidator({ required: true })]],
        penaltyType: [null, [penaltyTypeValidator({ required: true })]],
        bankName: [null, [bankNameValidator({ required: true })]],
      }),
    };
    this.databaseResponses = {
      loanInformation: null,
      paidBy: [],
      penaltyType: [],
      bankName: [],
      accessRight: [],
      transactionInformation: null,
    };
    this.pagingObject = {
      page: 1,
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      this.clientSearchCardSection.clientInformation = searchResult;
      switch (this.segmentSection.selectedSegment.windowCode) {
        case "5626": {
          await this.insertSegment(searchResult);
          break;
        }
        case "5633": {
          await this.editSegment(searchResult);
          break;
        }
        case "5634": {
          await this.deleteSegment(searchResult);
          break;
        }
      }
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async insertSegment(searchResult: SearchResult) {
    this.gridCardSection.insert.gridInformation = await this.transactionService
      .getUnexecutedPenaltiesByClientKey(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.insert.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.insert.visible = true;
    this.segmentSection.disable = true;
  }
  async editSegment(searchResult: SearchResult) {
    this.gridCardSection.edit.gridInformation = await this.transactionService
      .getUnexecutedPenaltiesPaymentByClientKey(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.edit.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.edit.visible = true;
    this.segmentSection.disable = true;
  }
  async deleteSegment(searchResult: SearchResult) {
    this.gridCardSection.delete.gridInformation = await this.transactionService
      .getUnexecutedPenaltiesPaymentByClientKey(searchResult.client_key)
      .toPromise();
    if (this.gridCardSection.delete.gridInformation.length === 0) {
      this.alertService.showAlertError("لا يوجد معلومات", false);
      return;
    }
    this.clientSearchCardSection.visible = false;
    this.gridCardSection.delete.visible = true;
    this.segmentSection.disable = true;
  }
  changePaginationPage = async (newPage: number) => {
    this.pagingObject.page = newPage;
  };
  backButton() {
    if (this.gridCardSection.insert.visible) {
      this.gridCardSection.insert.visible = false;
      this.gridCardSection.insert.gridInformation = [];
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.edit.visible) {
      this.gridCardSection.edit.visible = false;
      this.gridCardSection.edit.gridInformation = [];
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    } else if (this.gridCardSection.delete.visible) {
      this.gridCardSection.delete.visible = false;
      this.gridCardSection.delete.gridInformation = [];
      this.clientSearchCardSection = {
        visible: true,
        clientInformation: null,
      };
      this.segmentSection.disable = false;
      return;
    }
    if (this.loanInformationSection.visible) {
      this.loanInformationSection.checkIfInputsValid = false;
      this.loanInformationSection.visible = false;
      this.loanInformationSection.readonlyInformation = null;
      this.loanInformationSection.formGroup.reset();
      if (this.gridCardSection.insert.gridInformation.length)
        this.gridCardSection.insert.visible = true;
      if (this.gridCardSection.edit.gridInformation.length)
        this.gridCardSection.edit.visible = true;
      if (this.gridCardSection.delete.gridInformation.length)
        this.gridCardSection.delete.visible = true;
      return;
    }
  }
  async initiatePaymentForLoan(loanKey: number) {
    try {
      this.showLoader = true;
      const loan = this.gridCardSection.insert.gridInformation.find(
        (loan) => loan.loan_key === loanKey
      );
      this.loanInformationSection.readonlyInformation =
        this.extractReadonlyInformation(loan);
      this.databaseResponses.loanInformation = await this.loanService
        .getLoanInformationByLoanKey(loanKey)
        .toPromise();
      this.loanInformationSection.formGroup.patchValue({
        transactionAmount: 0,
      });
      this.gridCardSection.insert.visible = false;
      this.loanInformationSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async editingTransaction(transactionCode: number) {
    try {
      this.showLoader = true;
      this.gridCardSection.edit.visible = false;
      this.databaseResponses.transactionInformation =
        await this.transactionService
          .getUnexecutedPenaltyInformationForUpdate(transactionCode)
          .toPromise();
      this.loanInformationSection.readonlyInformation =
        this.extractReadonlyInformation(
          this.databaseResponses.transactionInformation
        );

      this.loanInformationSection.formGroup.patchValue({
        transactionAmount:
          this.databaseResponses.transactionInformation?.trans_loan_pen,
        transactionDate:
          this.databaseResponses.transactionInformation?.trans_act_date,
        penaltyType:
          this.databaseResponses.transactionInformation?.trans_loan_pen_type?.toString(),
        bankName: this.databaseResponses.transactionInformation?.trans_cur_bank,
        transactionInstallmentVoucher:
          this.databaseResponses.transactionInformation?.trans_inst_vouch?.toString(),
        paidBy:
          this.databaseResponses.transactionInformation?.paid_by?.toString(),
      });

      this.databaseResponses.loanInformation = await this.loanService
        .getLoanInformationByLoanKey(this.readonlyInformation.loanKey)
        .toPromise();

      this.loanInformationSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async getPenaltiesForSpecificLoan() {
    try {
      this.showLoader = true;
      const loanKey = this.loanInformationSection.readonlyInformation.loanKey;
      const penalties = await this.loanService
        .getPenaltiesReferenceByLoanKey(loanKey)
        .toPromise();
      this.alertService.showAlertInformation(
        `مبلغ الغرامة</br> ${penalties.pen_due}`,
        false
      );
    } catch (error) {
      if (error instanceof HttpErrorResponse) {
        this.alertService.showAlertError(JSON.stringify(error.error), false);
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }
  async insertPenaltyButton() {
    if (!this.loanInformationSection.formGroup.valid)
      return (this.loanInformationSection.checkIfInputsValid = true);
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.showLoader = true;
      const request: InsertUnexecutedPenalties = {
        loanKey: this.loanInformation.loanKey,
        loanUucString: this.loanInformation.loanUucString,
        paidBy: Number(this.loanInformationSection.formGroup.value.paidBy),
        transactionActualDate:
          this.loanInformationSection.formGroup.value.transactionDate,
        transactionCurrentBank:
          this.loanInformationSection.formGroup.value.bankName,
        transactionInstVoucher:
          this.loanInformationSection.formGroup.value
            .transactionInstallmentVoucher,
        transactionLoanPenalty:
          this.loanInformationSection.formGroup.value.transactionAmount,
        transactionLoanPenaltyType: Number(
          this.loanInformationSection.formGroup.value.penaltyType
        ),
      };
      await this.transactionService
        .insertUnexecutedPenalties(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      if (error instanceof HttpErrorResponse) {
        this.alertService.showAlertError(JSON.stringify(error.error), false);
        return;
      }
    } finally {
      this.showLoader = false;
    }
  }
  transactionSegmentChanging(event: any): void {
    const segmentEvent = event as SegmentCustomEvent;
    this.setSelectedTransactionSegment(segmentEvent.detail.value);
    this.resetClientSearchComponent();
  }
  setSelectedTransactionSegment(windowCode: string) {
    this.segmentSection.selectedSegment =
      this.segmentSection.allAvaliableSegments.find(
        (x) => x.windowCode === windowCode
      );
  }
  resetClientSearchComponent() {
    this.clientSearchCardSection.visible = false;
    setTimeout(() => (this.clientSearchCardSection.visible = true), 0);
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
  private extractReadonlyInformation(
    information:
      | GetUnexecutedPenaltiesByClientKey
      | GetUnexecutedPenaltyInformationForUpdate
  ): ReadonlyInformation {
    let staticClientInformation: ReadonlyInformation;

    if (this.segmentSection.selectedSegment.windowCode === "5626") {
      const info = information as GetUnexecutedPenaltiesByClientKey;
      staticClientInformation =
        this.mapUnexecutedPenaltiesByClientKeyInfo(info);
    } else {
      const info = information as GetUnexecutedPenaltyInformationForUpdate;
      staticClientInformation =
        this.mapUnexecutedPenaltiesPaymentByClientKeyInfo(info);
    }

    return staticClientInformation;
  }
  private mapUnexecutedPenaltiesByClientKeyInfo(
    info: GetUnexecutedPenaltiesByClientKey
  ): ReadonlyInformation {
    return {
      clientCode: `${info.org_branch_code}/${info.client_code}`,
      clientName: info.client_name,
      funderName: info.funder_name,
      issuingBank: info.disb_bank_name,
      loanAmount: info.loan_am,
      loanCode: info.loan_code,
      loanDate: info.loan_date,
      loanInterest: info.loan_int_am,
      loanPenalities: info.loan_penalties,
      loanKey: info.loan_key,
    };
  }
  private mapUnexecutedPenaltiesPaymentByClientKeyInfo(
    info: GetUnexecutedPenaltyInformationForUpdate
  ): ReadonlyInformation {
    return {
      clientCode: info.client_no,
      clientName: info.client_name,
      funderName: info.funder_name,
      issuingBank: info.disb_bank_name,
      loanAmount: info.loan_am,
      loanCode: info.loan_code,
      loanDate: info.loan_date,
      loanInterest: info.loan_int_am,
      loanPenalities: info.loan_penalties,
      loanKey: info.loan_key,
    };
  }
  async updateTransactionButton() {
    this.loanInformationSection.checkIfInputsValid = true;
    if (!this.loanInformationSection.formGroup.valid) return;
    if (!(await this.alertService.SaveAlert())) return;

    try {
      this.showLoader = true;
      const { value } = this.loanInformationSection.formGroup;
      const { transactionInformation } = this.databaseResponses;
      const request: UpdateUnexecutedPenalty = {
        paidBy: Number(value.paidBy),
        transactionCode: transactionInformation.trans_code,
        transactionCurrentBank: value.bankName,
        transactionDate: value.transactionDate,
        transactionLoanPenalty: value.transactionAmount,
        transactionLoanPenaltyType: Number(value.penaltyType),
        transactionUuc: transactionInformation.uuc_trans,
        transactionVoucher:
          value.transactionInstallmentVoucher === undefined ||
          value.transactionInstallmentVoucher === ""
            ? null
            : value.transactionInstallmentVoucher,
      };
      console.log(request);
      await this.transactionService
        .updateUnexecutedPenalty(request)
        .toPromise();

      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  async deleteSpecificTransaction(transactionCode: number) {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      this.showLoader = true;
      this.databaseResponses.transactionInformation =
        await this.transactionService
          .getUnexecutedPenaltyInformationForUpdate(transactionCode)
          .toPromise();
      const request: DeleteUnexecutedPenalty = {
        transactionCode: transactionCode,
        transactionUuc: this.databaseResponses.transactionInformation.uuc_trans,
      };
      await this.transactionService
        .deleteUnexecutedPenalty(request)
        .toPromise();
      this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
}
